using namespace std;
namespace phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=gc();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
	}
}
using namespace phigrOS;
int x,y,a,b,k;
short h[10000001];
int len(int x,int k)
{
	int c=0;
	wh(x)
	{
		x/=k;
		++c;
	}
	return c;
}
int mk(int a,int b,int l,int k)
{
	int x=0;
	FOR(i,1,l)
	{
		if(i&1)
			x=x*k+a;
		else
			x=x*k+b;
	}
	return x;
}
void srch(int k)
{
	int l=len(a,k),r=len(b,k);
	FOR(i,1,k-1)
	{
		FOR(j,0,k-1)
		{
			if(i==j)
				continue;
			FOR(u,l,r)
			{
				int n=mk(i,j,u,k);
				if(n>=a&&n<=b)
					h[n]++;
			}
		}
	}
}
signed main()
{
	x=read();
	y=read();
	a=read();
	b=read();
	k=read();
	FOR(i,x,y)
	{
		srch(i);
	}
	FOR(i,a,b)
	{
		if(h[i]==k)
			writeln(i);
	}
	return 0;
}
